import math
from typing import List, Tuple, Dict

class ShoppingOptimizer:
    def __init__(self):
        self.memo: Dict[Tuple[int, ...], int] = {}
        self.num_items: int = 0
        self.price: List[int] = []
        self._all_purchase_options: List[List[int]] = []

    def solve(self, price: List[int], initial_special_offers: List[List[int]], needs: List[int]) -> int:
        self.num_items = len(price)
        self.price = price
        self.memo = {}

        self._all_purchase_options = []

        for offer in initial_special_offers:
            if len(offer) == self.num_items + 1:
                self._all_purchase_options.append(offer)

        for i in range(self.num_items):
            individual_offer = [0] * self.num_items
            individual_offer[i] = 1
            individual_offer.append(self.price[i])
            self._all_purchase_options.append(individual_offer)

        return self._min_cost_recursive(tuple(needs))

    def _min_cost_recursive(self, current_needs_tuple: Tuple[int, ...]) -> int:
        if current_needs_tuple in self.memo:
            return self.memo[current_needs_tuple]

        if all(n == 0 for n in current_needs_tuple):
            return 0

        min_c = math.inf

        for offer in self._all_purchase_options:
            offer_items_qty = offer[:-1]
            offer_price = offer[-1]

            can_apply_offer = True
            next_needs_list = list(current_needs_tuple)

            for i in range(self.num_items):
                if offer_items_qty[i] > next_needs_list[i]:
                    can_apply_offer = False
                    break

            if can_apply_offer:
                for i in range(self.num_items):
                    next_needs_list[i] -= offer_items_qty[i]

                cost_with_offer = offer_price + self._min_cost_recursive(tuple(next_needs_list))
                min_c = min(min_c, cost_with_offer)

        self.memo[current_needs_tuple] = min_c
        return min_c
